#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    long long ans = 0;
    for (int i = 0; i < n; i++) {
        long long x = 0;
        for (int j = 0; j <= i; j++) {
            x ^= a[j];
        }
        ans += x;
    }
    printf("%lld\n", ans);
    return 0;
}

