const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        let ans = 0;
        for (let i = 0; i < n; i++) {
            let x = 0;
            for (let j = 0; j <= i; j++) {
                x ^= a[j];
            }
            ans += x;
        }
        console.log(ans);
        rl.close();
    }
});
